#include <stdio.h>
#include <stdlib.h>
#define MOD 19101995
#define MAXN 100000

int N;
int adj[MAXN][MAXN];
int deg[MAXN];

void dfs(int u, int p) {
    int i;
    for (i = 0; i < N; i++) {
        if (adj[u][i] && i != p) {
            dfs(i, u);
            deg[u]++;
        }
    }
}

int count_decompositions(int u, int p) {
    int i;
    int res = 1;
    for (i = 0; i < N; i++) {
        if (adj[u][i] && i != p) {
            res = (res * count_decompositions(i, u)) % MOD;
        }
    }
    if (deg[u] > 1) {
        res = (res * deg[u]) % MOD;
    }
    return res;
}

int main() {
    int i, j;
    scanf("%d", &N);
    for (i = 0; i < N - 1; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        u--; v--;
        adj[u][v] = adj[v][u] = 1;
    }
    dfs(0, -1);
    printf("%d\n", count_decompositions(0, -1));
    return 0;
}

