import java.util.Scanner;
import java.util.ArrayList;

public class Main {
    static final int MOD = 19101995;
    static final int MAXN = 100000;
    static int N;
    static int[][] adj = new int[MAXN][MAXN];
    static int[] deg = new int[MAXN];

    public static void dfs(int u, int p) {
        for (int i = 0; i < N; i++) {
            if (adj[u][i] == 1 && i != p) {
                dfs(i, u);
                deg[u]++;
            }
        }
    }

    public static int count_decompositions(int u, int p) {
        int res = 1;
        for (int i = 0; i < N; i++) {
            if (adj[u][i] == 1 && i != p) {
                res = (res * count_decompositions(i, u)) % MOD;
            }
        }
        if (deg[u] > 1) {
            res = (res * deg[u]) % MOD;
        }
        return res;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        N = sc.nextInt();
        for (int i = 0; i < N - 1; i++) {
            int u = sc.nextInt() - 1;
            int v = sc.nextInt() - 1;
            adj[u][v] = adj[v][u] = 1;
        }
        dfs(0, -1);
        System.out.println(count_decompositions(0, -1));
    }
}

