const MOD = 19101995;
const MAXN = 100000;

let N = parseInt(lines[idx++]);
let adj = Array.from({ length: N }, () => []);
let deg = Array.from({ length: N }, () => 0);

for (let i = 0; i < N - 1; i++) {
    let [u, v] = lines[idx++].trim().split(' ').map(Number);
    u--;
    v--;
    adj[u].push(v);
    adj[v].push(u);
}

function dfs(u, p) {
    for (let i of adj[u]) {
        if (i !== p) {
            dfs(i, u);
            deg[u]++;
        }
    }
}

function count_decompositions(u, p) {
    let res = 1;
    for (let i of adj[u]) {
        if (i !== p) {
            res = (res * count_decompositions(i, u)) % MOD;
        }
    }
    if (deg[u] > 1) {
        res = (res * deg[u]) % MOD;
    }
    return res;
}

